mapper.select:
SELECT order_date::DATE as "date", COUNT(*) as "orderCount", COALESCE(SUM(total_amount), 0) as "revenue" FROM hm_query.order_details_flat
AND order_status NOT IN ('CANCELLED', 'PAYMENT_FAILED') AND order_date::DATE >= CAST(#{startDate} AS DATE) AND order_date::DATE <= CAST(#{endDate} AS DATE) AND (order_number ILIKE CONCAT('%', #{q}, '%') OR customer_id ILIKE CONCAT('%', #{q}, '%'))
GROUP BY order_date::DATE ${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.order_details_flat

    AND (order_number ILIKE CONCAT('%', #{q}, '%') OR customer_id ILIKE CONCAT('%', #{q}, '%'))
    AND order_status = #{stateId}

SELECT o.order_id as "id", o.order_number as "orderNumber", o.order_status as "stateId", o.total_amount as "total", o.currency as "currency", o.order_date as "createdTime", o.total_items as "itemCount", o.customer_id as "customerId" FROM hm_query.order_details_flat o
AND (o.order_number ILIKE CONCAT('%', #{q}, '%') OR o.customer_id ILIKE CONCAT('%', #{q}, '%')) AND o.order_status = #{stateId}
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.audit_log_flat

    AND entity_type = #{entityType}
    AND action = #{action}
    AND changed_by = #{changedBy}
    AND created_time >= CAST(#{startDate} AS TIMESTAMP)
    AND created_time <= CAST(#{endDate} AS TIMESTAMP)
    AND (entity_type ILIKE CONCAT('%', #{q}, '%') OR entity_id ILIKE CONCAT('%', #{q}, '%') OR changed_by ILIKE CONCAT('%', #{q}, '%'))

SELECT al.id as "id", al.entity_type as "entityType", al.entity_id as "entityId", al.action as "action", al.old_value as "oldValue", al.new_value as "newValue", al.changed_by as "changedBy", al.ip_address as "ipAddress", al.correlation_id as "correlationId", al.is_critical as "isCritical", al.details as "details", al.created_time as "createdTime" FROM hm_query.audit_log_flat al
AND al.entity_type = #{entityType} AND al.action = #{action} AND al.changed_by = #{changedBy} AND al.created_time >= CAST(#{startDate} AS TIMESTAMP) AND al.created_time <= CAST(#{endDate} AS TIMESTAMP) AND (al.entity_type ILIKE CONCAT('%', #{q}, '%') OR al.entity_id ILIKE CONCAT('%', #{q}, '%') OR al.changed_by ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
